import { describe, expect, it } from 'vitest';

import {
  BANDWIDTH_TRITON,
  ImageCarrierPipeline,
} from '../src/index';

describe('ImageCarrierPipeline image analysis', () => {
  it('classifies each patch under all observer bandwidths', () => {
    const pipeline = new ImageCarrierPipeline({
      carrierBandwidth: 54,
      observerBandwidths: [3, 54],
    });
    const analysis = pipeline.analyze({
      width: 2,
      height: 1,
      channels: 1,
      sampleRange: 'unit',
      data: new Float32Array([2 / 54, 53 / 54]),
    });

    expect(analysis.carrierBandwidth).toBe(54);
    expect(analysis.patchColumns).toBe(2);
    expect(analysis.patchRows).toBe(1);
    expect(analysis.patches).toHaveLength(2);
    expect(analysis.patches[0]!.stepOrigin).toBe(2);
    expect(analysis.patches[0]!.readings.map((r) => r.reading)).toEqual([
      'evolution',
      'resolution',
    ]);
    expect(analysis.patches[1]!.stepOrigin).toBe(53);
    expect(analysis.patches[1]!.readings.map((r) => r.reading)).toEqual([
      'evolution',
      'evolution',
    ]);
  });

  it('keeps Bule +1 cost invariant across bandwidths', () => {
    const pipeline = new ImageCarrierPipeline({
      observerBandwidths: [3, 6, 54],
      patchSize: 1,
    });
    const analysis = pipeline.analyze({
      width: 2,
      height: 2,
      channels: 1,
      sampleRange: 'unit',
      data: new Float32Array([0, 2 / 54, 17 / 54, 1]),
    });

    expect(analysis.buleCostInvariantAcrossBandwidths).toBe(true);
    expect(analysis.summaries.map((summary) => summary.totalBuleCost)).toEqual([
      4,
      4,
      4,
    ]);
  });

  it('averages RGB luminance inside larger patches', () => {
    const pipeline = new ImageCarrierPipeline({
      observerBandwidths: [BANDWIDTH_TRITON],
      patchSize: 2,
    });
    const analysis = pipeline.analyze({
      width: 2,
      height: 1,
      channels: 3,
      sampleRange: 'byte',
      data: new Uint8Array([
        255, 0, 0,
        0, 255, 0,
      ]),
    });

    expect(analysis.patches).toHaveLength(1);
    expect(analysis.patches[0]!.meanLuminance).toBeCloseTo(
      (0.2126 + 0.7152) / 2,
    );
  });

  it('rejects invalid image shape and carrier settings', () => {
    expect(() => new ImageCarrierPipeline({ observerBandwidths: [] })).toThrow(
      /observerBandwidths/,
    );
    expect(
      () => new ImageCarrierPipeline({ carrierBandwidth: 54, highBandwidth: 3 }),
    ).toThrow(/carrierBandwidth/);
    const pipeline = new ImageCarrierPipeline();
    expect(() =>
      pipeline.analyze({
        width: 2,
        height: 2,
        channels: 1,
        data: new Float32Array(3),
      }),
    ).toThrow(/data length/);
  });
});
